'use strict';
/**
 * ================================================================
 *  ORDER PAGE — logic, rendering, cart management
 *  ================================================================
 *  Do not edit this file for normal customisation.
 *  All brand/menu/schedule data lives in config.js.
 * ================================================================
 */

/* ── ITEM LOOKUP MAP ────────────────────────────────────────── */
const ITEM_MAP = {};
MENU.forEach(cat => cat.items.forEach(item => { ITEM_MAP[item.id] = item; }));
const COUPONS = BRAND.coupons || {};

/* ── ICON SVGS ───────────────────────────────────────────────── */
const PLUS_SVG  = `<svg width="16" height="16" viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" aria-hidden="true" style="pointer-events:none"><line x1="8" y1="2" x2="8" y2="14"/><line x1="2" y1="8" x2="14" y2="8"/></svg>`;
const MINUS_SVG = `<svg width="12" height="12" viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" aria-hidden="true" style="pointer-events:none"><line x1="1" y1="6" x2="11" y2="6"/></svg>`;

/* ── STATE ──────────────────────────────────────────────────── */
const cart = {};                    // { itemId: qty }
let payMethod      = 'ideal';       // 'ideal' | 'cash'
let fulfillMethod  = 'delivery';    // 'delivery' | 'pickup'
let tipAmount      = 0;             // euros, added at checkout
let couponCode     = '';
let couponDiscount = 0;             // fraction, e.g. 0.09 for 9%
let restaurantOpen = true;          // set by initOpenCheck() on load
let restaurantCoords        = null;  // { lat, lng } — set by initDeliveryZone() on load
let selectedDeliveryAddress = null;  // { label, lat, lng } — set when user picks from autocomplete
let _addrDebounceTimer      = null;
let scheduledTime           = null;  // 'asap' or 'HH:MM' — set in placeOrder()
let selectedOrderDate       = null;  // null = today, or 'YYYY-MM-DD' Amsterdam date string
let timingMode              = 'asap'; // 'asap' | 'scheduled'
let calYear                 = null;   // Amsterdam year of displayed calendar month
let calMonth                = null;   // Amsterdam month (1-12) of displayed calendar month
const MIN               = BRAND.min_order;
const CART_KEY          = 'restaurant_cart';
const CHECKOUT_FIELDS_KEY = 'restaurant_checkout_fields';

/* ── BOOTSTRAP ──────────────────────────────────────────────── */
document.addEventListener('DOMContentLoaded', () => {
  applyBrand();
  renderCategoryNav();
  renderMenu();
  loadCart();
  Object.keys(cart).forEach(id => refreshCtrl(id));
  initScrollSpy();
  initNavScroll();
  initMobileNav();
  initOpenCheck();      // ← time-gate: must run before first refreshUI
  initDeliveryZone();   // pre-fetch restaurant coords in background
  initPhoneValidation();
  initEmailValidation();
  initTipInput();
  initCouponInput();
  refreshUI();
  document.addEventListener('click', e => {
    if (!e.target.closest('#calField')) closeCalPopup();
  });
});

/* ── BRAND INJECTION ────────────────────────────────────────── */
function applyBrand() {
  q('[data-brand="name"]',    el => el.textContent = BRAND.name);
  q('[data-brand="tagline"]', el => el.textContent = BRAND.tagline);

  const telHref = `tel:${BRAND.phone.replace(/\s/g, '')}`;
  const navPhone = qs('#navPhone');
  if (navPhone) {
    navPhone.href = telHref;
    const numEl = navPhone.querySelector('.nav-phone-num');
    if (numEl) numEl.textContent = BRAND.phone;
  }
  const mobileNavPhone = qs('#mobileNavPhone');
  if (mobileNavPhone) {
    mobileNavPhone.href = telHref;
    mobileNavPhone.innerHTML = `<iconify-icon icon="ph:phone" width="14" height="14" aria-hidden="true"></iconify-icon> ${BRAND.phone}`;
  }

  const logoImg = qs('.nav-logo-img');
  if (BRAND.logo_img && logoImg) {
    logoImg.src = BRAND.logo_img;
    logoImg.style.display = '';
    document.getElementById('favicon').href = BRAND.logo_img;
  }
}

/* ── CATEGORY NAV ───────────────────────────────────────────── */
function renderCategoryNav() {
  const sidebar = qs('#catSidebar');
  if (sidebar) {
    sidebar.innerHTML = MENU.map((cat, i) => `
      <button class="cat-link${i===0?' active':''}"
              data-target="${cat.id}"
              onclick="goToCategory('${cat.id}',this)">
        <span class="cat-link-emoji"><iconify-icon icon="${cat.icon || cat.emoji}" width="16" height="16" aria-hidden="true"></iconify-icon></span>${cat.label}
      </button>`).join('');
  }

  const tabs = qs('#mobileTabs');
  if (tabs) {
    tabs.innerHTML = MENU.map((cat, i) => `
      <button class="m-tab${i===0?' active':''}"
              data-target="${cat.id}"
              onclick="goToCategory('${cat.id}',this)">
        ${cat.label}
      </button>`).join('');
  }
}

/* ── MENU RENDERING ─────────────────────────────────────────── */
function renderMenu() {
  const el = qs('#menuContent');
  if (!el) return;
  el.innerHTML = MENU.map(cat => `
    <div class="menu-section" id="ms-${cat.id}">
      <h2 class="menu-section-title"><iconify-icon icon="${cat.icon || cat.emoji}" width="22" height="22" aria-hidden="true"></iconify-icon>${cat.label}</h2>
      <div class="items-grid">
        ${cat.items.map(buildCard).join('')}
      </div>
    </div>`).join('');
}

function buildCard(item) {
  const src      = item.image || '';
  const hasImg   = !!src;
  const priceStr = item.price === 0 ? 'Gratis' : fmt(item.price);
  const badge    = item.recommended ? '<span class="item-badge"><iconify-icon icon="ph:star-fill" width="10" height="10" aria-hidden="true" style="vertical-align:-1px;margin-right:3px"></iconify-icon>Aanbevolen</span>' : '';

  return `
<article class="item-card" id="card-${item.id}">
  ${badge}
  <div class="item-img-wrap">
    <img class="item-img"
         src="${src}"
         data-item="${item.id}"
         alt="${item.name}"
         style="${hasImg ? '' : 'display:none'}"
         onerror="this.style.display='none';this.nextElementSibling.style.display='flex'">
    <div class="item-img-ph" style="${hasImg ? 'display:none' : ''}">${item.emoji}</div>
  </div>
  <div class="item-body">
    <div class="item-header">
      <span class="item-name">${item.name}</span>
    </div>
    <p class="item-desc">${item.desc}</p>
    <div class="item-foot">
      <span class="item-price">${priceStr}</span>
      <div id="ctrl-${item.id}">
        <button class="add-btn" onclick="addItem('${item.id}')" aria-label="Toevoegen aan bestelling">${PLUS_SVG}</button>
      </div>
    </div>
  </div>
</article>`;
}

/* ── CART OPERATIONS ────────────────────────────────────────── */
function addItem(id) {
  cart[id] = (cart[id] || 0) + 1;
  refreshCtrl(id);
  refreshUI();
  bumpCartIcon();
  saveCart();
}

function removeItem(id) {
  if (!cart[id]) return;
  cart[id]--;
  if (cart[id] <= 0) delete cart[id];
  refreshCtrl(id);
  refreshUI();
  saveCart();
}

function refreshCtrl(id) {
  const el  = qs(`#ctrl-${id}`);
  if (!el) return;
  const qty = cart[id] || 0;

  if (qty === 0) {
    el.innerHTML = `<button class="add-btn" onclick="addItem('${id}')" aria-label="Toevoegen">${PLUS_SVG}</button>`;
    const btn = el.querySelector('.add-btn');
    btn.classList.add('pop');
    btn.addEventListener('animationend', () => btn.classList.remove('pop'), { once: true });
  } else {
    el.innerHTML = `
      <div class="qty-ctrl">
        <button class="qty-btn minus" onclick="removeItem('${id}')">${MINUS_SVG}</button>
        <span class="qty-val">${qty}</span>
        <button class="qty-btn plus"  onclick="addItem('${id}')">${PLUS_SVG}</button>
      </div>`;
  }
}

function cartTotal() {
  return Object.entries(cart).reduce((s, [id, q]) => s + ITEM_MAP[id].price * q, 0);
}
function cartCount() {
  return Object.values(cart).reduce((s, q) => s + q, 0);
}
function discountedTotal() {
  const raw = cartTotal();
  return couponDiscount > 0 ? +(raw * (1 - couponDiscount)).toFixed(2) : raw;
}


/* ── GLOBAL UI REFRESH ──────────────────────────────────────── */
function refreshUI() {
  const total  = cartTotal();
  const count  = cartCount();
  const fTotal = fmt(total);
  const below  = count > 0 && total < MIN;

  qAll('[data-cart-count]').forEach(el => {
    el.textContent   = count;
    el.style.display = count ? '' : 'none';
  });

  qAll('[data-cart-total]').forEach(el => el.textContent = fTotal);

  const bar = qs('#floatBar');
  if (bar) {
    bar.classList.toggle('show', count > 0);
    const bc = qs('#fbCount'); if (bc) bc.textContent = count;
    const bp = qs('#fbPrice'); if (bp) bp.textContent = fTotal;
  }

  qAll('[data-min-warn]').forEach(el => {
    el.style.display = below ? '' : 'none';
    el.innerHTML     = `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" style="vertical-align:-2px;margin-right:5px"><path d="m21.73 18-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z"/><path d="M12 9v4"/><path d="M12 17h.01"/></svg>Minimale bestelling ${fmt(MIN)} voor bezorging`;
  });

  /* Disable order button when cart is empty, below minimum, or closed with no slots at all */
  qAll('[data-order-btn]').forEach(btn => {
    const maxDays = BRAND.scheduling?.max_days_ahead ?? 0;
    const closedNoSlots = !restaurantOpen &&
      generateTimeSlots('delivery').length === 0 &&
      generateTimeSlots('pickup').length === 0 &&
      maxDays === 0;
    btn.disabled = count === 0 || below || closedNoSlots;
  });

  qAll('[data-cart-empty]').forEach(el => el.style.display = count ? 'none' : '');
  qAll('[data-cart-filled]').forEach(el => el.style.display = count ? '' : 'none');

  const vatFactor = 1 - couponDiscount;
  const vatStr    = count > 0 ? vatHtml(getVatBreakdown(), vatFactor) : '';
  qAll('[data-cart-vat]').forEach(el => {
    if (!vatStr) { el.style.display = 'none'; return; }
    el.innerHTML = vatStr;
    el.style.display = '';
  });

  if (couponDiscount > 0) updateCouponUI();

  renderCartList('cartItems');
  renderCartList('drawerItems');
}

function renderCartList(containerId) {
  const el = qs(`#${containerId}`);
  if (!el) return;
  const entries = Object.entries(cart);
  if (!entries.length) { el.innerHTML = ''; return; }

  el.innerHTML = entries.map(([id, qty]) => {
    const item = ITEM_MAP[id];
    return `
<div class="cart-row">
  <div class="cart-row-info">
    <span class="cart-row-name">${item.name}</span>
    <span class="cart-row-sub">${fmt(item.price * qty)}</span>
  </div>
  <div class="cart-row-qty">
    <button class="cqb minus" onclick="removeItem('${id}')">${MINUS_SVG}</button>
    <span>${qty}</span>
    <button class="cqb plus"  onclick="addItem('${id}')">${PLUS_SVG}</button>
  </div>
</div>`;
  }).join('');
}

/* ── CART DRAWER (mobile / tablet) ─────────────────────────── */
function openDrawer() {
  qs('#cartDrawer')?.classList.add('open');
  qs('#drawerOverlay')?.classList.add('open');
  document.body.style.overflow = 'hidden';
}

function closeDrawer() {
  qs('#cartDrawer')?.classList.remove('open');
  qs('#drawerOverlay')?.classList.remove('open');
  document.body.style.overflow = '';
}

/* ── FULFILLMENT (DELIVERY / PICKUP) ────────────────────────── */
function selectFulfillment(method) {
  fulfillMethod = method;
  qs('#fOptDelivery')?.classList.toggle('selected', method === 'delivery');
  qs('#fOptPickup')?.classList.toggle('selected',   method === 'pickup');

  /* Address field: required for delivery, hidden for pickup */
  const addrRow   = qs('#addressRow');
  const pickupNote = qs('#pickupNote');
  if (addrRow)    addrRow.style.display    = method === 'pickup' ? 'none' : '';
  if (pickupNote) pickupNote.style.display = method === 'pickup' ? '' : 'none';

  /* Update cash label: delivery vs pickup context */
  const cashLabel = qs('#cashLabel');
  if (cashLabel) cashLabel.textContent = method === 'pickup' ? 'Contant bij afhalen' : 'Contant bij bezorging';

  selectedDeliveryAddress = null;
  clearAddrError();
  closeAddrDropdown();
  initScheduling();
  if (timingMode === 'scheduled') updateCalTriggerLabel();
}

/* ── CHECKOUT ────────────────────────────────────────────────── */
function openCheckout() {
  closeDrawer();

  /* Reset timing and fulfillment to defaults each time checkout opens */
  selectedOrderDate = null;
  timingMode        = restaurantOpen ? 'asap' : 'scheduled';
  const _tp         = getAmsterdamDateParts(new Date());
  calYear  = _tp.year;
  calMonth = _tp.month;
  const _asapOpt = qs('#tOptAsap');
  if (_asapOpt) _asapOpt.style.display = restaurantOpen ? '' : 'none';
  selectFulfillment('delivery');
  selectTiming(timingMode);

  /* Populate pickup address and note from config */
  const addrStr = `${BRAND.address.street}, ${BRAND.address.postal} ${BRAND.address.city}`;
  const pickupDescEl = qs('#pickupAddrLine');
  if (pickupDescEl) pickupDescEl.textContent = addrStr;
  const pickupFullEl = qs('#pickupAddrFull');
  if (pickupFullEl) pickupFullEl.textContent = addrStr;
  const pickupWaitEl = qs('#pickupWait');
  if (pickupWaitEl) pickupWaitEl.textContent = BRAND.pickup?.note || '';

  /* Show/hide pickup option based on config */
  const pickupOpt = qs('#fOptPickup');
  if (pickupOpt) pickupOpt.style.display = BRAND.pickup?.available ? '' : 'none';

  /* Populate order summary */
  const sumEl = qs('#coSummary');
  if (sumEl) {
    sumEl.innerHTML = Object.entries(cart).map(([id, qty]) => {
      const item = ITEM_MAP[id];
      return `
<div class="co-row">
  <span>${item.name} <span class="co-qty">×${qty}</span></span>
  <span class="co-price">${fmt(item.price * qty)}</span>
</div>`;
    }).join('');
  }
  const coTot = qs('#coTotal');
  if (coTot) coTot.textContent = fmt(cartTotal());

  /* Show closed notice when store is closed (scheduled order) */
  const coNotice = qs('#coClosedNotice');
  if (coNotice) coNotice.style.display = restaurantOpen ? 'none' : '';

  /* Reflect coupon applied at cart stage */
  updateCouponUI();

  /* Reset tip */
  tipAmount = 0;
  const tipInput = qs('#tipCustom');
  if (tipInput) tipInput.value = '';
  const tipCustomWrap = qs('#tipCustomWrap');
  if (tipCustomWrap) tipCustomWrap.style.display = 'none';
  renderTipBtns(discountedTotal());
  updateTipUI();

  restoreCheckoutFields();

  qs('#checkoutModal')?.classList.add('open');
  qs('#checkoutOverlay')?.classList.add('open');
  document.body.style.overflow = 'hidden';
}

function closeCheckout() {
  qs('#checkoutModal')?.classList.remove('open');
  qs('#checkoutOverlay')?.classList.remove('open');
  document.body.style.overflow = '';
}

function selectPay(method) {
  payMethod = method;
  qs('#payIdeal')?.classList.toggle('selected', method === 'ideal');
  qs('#payCard')?.classList.toggle('selected',  method === 'card');
  qs('#payCash')?.classList.toggle('selected',  method === 'cash');
}

function placeOrder() {
  const naam = val('fNaam');
  const tel  = val('fTel');

  if (!naam) {
    alert('Vul uw naam in.');
    return;
  }

  clearTelError();
  if (!tel || !isValidDutchPhone(tel)) {
    showTelError(tel ? 'Voer een geldig Nederlands telefoonnummer in (bijv. 06 12 34 56 78).' : 'Vul uw telefoonnummer in.');
    qs('#fTel')?.focus();
    return;
  }

  const email = val('fEmail');
  clearEmailError();
  if (!email || !isValidEmail(email)) {
    showEmailError(email ? 'Voer een geldig e-mailadres in (bijv. naam@voorbeeld.nl).' : 'Vul uw e-mailadres in.');
    qs('#fEmail')?.focus();
    return;
  }

  if (fulfillMethod === 'delivery') {
    if (!selectedDeliveryAddress) {
      showAddrError('Selecteer een adres uit de lijst hieronder.');
      qs('#fAdres')?.focus();
      return;
    }

    if (BRAND.delivery_radius_km > 0 && restaurantCoords) {
      const km = haversineKm(restaurantCoords, selectedDeliveryAddress);
      if (km > BRAND.delivery_radius_km) {
        showAddrError(
          `Helaas bezorgen wij niet op dit adres. Ons bezorggebied is ${BRAND.delivery_radius_km} km rondom het restaurant (uw adres ligt op ca. ${km.toFixed(1)} km).`
        );
        return;
      }
    }
  }

  /* Validate and capture scheduled time */
  if (timingMode === 'scheduled') {
    const timeVal = qs('#fTijd')?.value || '';
    if (!timeVal) {
      const errEl = qs('#timeError');
      if (errEl) { errEl.textContent = 'Kies een tijdstip.'; errEl.style.display = ''; }
      return;
    }
    const targetDate = selectedOrderDate ? dateFromAmsterdamISO(selectedOrderDate) : new Date();
    if (isSameAmsterdamDay(targetDate, new Date())) {
      const { min: nowMin } = getAmsterdamDayMin();
      const [sh, sm] = timeVal.split(':').map(Number);
      const prepMin  = fulfillMethod === 'pickup'
        ? (BRAND.scheduling?.pickup_prep_min ?? 20)
        : (BRAND.scheduling?.delivery_prep_min ?? 35);
      if (nowMin + prepMin > sh * 60 + sm) {
        const errEl = qs('#timeError');
        if (errEl) { errEl.textContent = 'Dit tijdstip is niet meer beschikbaar. Kies een ander tijdstip.'; errEl.style.display = ''; }
        initScheduling();
        return;
      }
    }
    scheduledTime = timeVal;
  } else {
    scheduledTime = 'asap';
  }

  saveCheckoutFields();

  if (payMethod === 'ideal' || payMethod === 'card') {
    initiateStripeCheckout();
  } else {
    closeCheckout();
    setTimeout(() => qs('#confirmScreen')?.classList.add('open'), 280);
  }
}

async function initiateStripeCheckout() {
  const btn = qs('#placeOrderBtn');
  if (btn) { btn.disabled = true; btn.textContent = 'Doorsturen naar betaling…'; }

  const discount = couponDiscount || 0;
  const items    = [];
  Object.entries(cart).forEach(([id, qty]) => {
    if (qty <= 0) return;
    const item = ITEM_MAP[id];
    if (!item) return;
    items.push({ name: item.name, price: item.price * (1 - discount), qty });
  });
  if (tipAmount > 0) items.push({ name: 'Fooi', price: tipAmount, qty: 1 });

  const timeLabel = (() => {
    if (!scheduledTime || scheduledTime === 'asap') return 'Zo snel mogelijk';
    const td = selectedOrderDate ? dateFromAmsterdamISO(selectedOrderDate) : new Date();
    if (isSameAmsterdamDay(td, new Date())) return scheduledTime;
    const dateLbl = new Intl.DateTimeFormat('nl-NL', {
      timeZone: 'Europe/Amsterdam', weekday: 'long', day: 'numeric', month: 'long',
    }).format(td);
    return `${dateLbl} om ${scheduledTime}`;
  })();

  const metadata = {
    naam:          val('fNaam'),
    telefoon:      val('fTel'),
    bezorgwijze:   fulfillMethod === 'pickup' ? 'Afhalen' : 'Bezorgen',
    adres:         fulfillMethod === 'delivery'
                     ? (selectedDeliveryAddress?.label || '')
                     : `${BRAND.address.street}, ${BRAND.address.postal} ${BRAND.address.city}`,
    gewenste_tijd: timeLabel,
  };
  const note = val('fNote');
  if (note)       metadata.opmerking    = note;
  if (couponCode) metadata.kortingscode = couponCode;

  try {
    const resp = await fetch('/api/checkout', {
      method:  'POST',
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify({ items, paymentMethod: payMethod, customer_email: val('fEmail'), metadata }),
    });
    const data = await resp.json();
    if (data.url) {
      try {
        localStorage.setItem('restaurant_order_meta', JSON.stringify({
          fulfillMethod,
          scheduledTime: scheduledTime || 'asap',
          naam: val('fNaam'),
        }));
      } catch {}
      window.location.href = data.url;
    } else {
      alert(data.error || 'Er is een fout opgetreden. Probeer het opnieuw.');
      if (btn) { btn.disabled = false; btn.textContent = 'Bestelling plaatsen'; }
    }
  } catch {
    alert('Verbindingsfout. Controleer uw internet en probeer het opnieuw.');
    if (btn) { btn.disabled = false; btn.textContent = 'Bestelling plaatsen'; }
  }
}

/* ── DELIVERY ZONE ───────────────────────────────────────────── */
function initDeliveryZone() {
  /* Pre-fetch restaurant coordinates in background */
  if (BRAND.delivery_radius_km > 0 && BRAND.address?.postal) {
    geocodeRestaurant();
  }
  initAddressAutocomplete();
}

async function geocodeRestaurant() {
  try {
    const q = encodeURIComponent(BRAND.address.postal.trim() + ', Nederland');
    const r = await fetch(`https://nominatim.openstreetmap.org/search?q=${q}&format=json&limit=1&countrycodes=nl`);
    const d = await r.json();
    if (d.length) restaurantCoords = { lat: parseFloat(d[0].lat), lng: parseFloat(d[0].lon) };
  } catch { /* fail silently */ }
}

function haversineKm(a, b) {
  const R = 6371, rad = x => x * Math.PI / 180;
  const dLat = rad(b.lat - a.lat), dLng = rad(b.lng - a.lng);
  const x = Math.sin(dLat / 2) ** 2 + Math.cos(rad(a.lat)) * Math.cos(rad(b.lat)) * Math.sin(dLng / 2) ** 2;
  return R * 2 * Math.asin(Math.sqrt(x));
}

/* ── ADDRESS AUTOCOMPLETE (PDOK Locatieserver) ───────────────── */
function initAddressAutocomplete() {
  const input    = qs('#fAdres');
  const dropdown = qs('#addrDropdown');
  if (!input || !dropdown) return;

  input.addEventListener('input', () => {
    clearAddrError();
    selectedDeliveryAddress = null;
    input.classList.remove('addr-selected');

    const q = input.value.trim();
    if (q.length < 3) { closeAddrDropdown(); return; }

    clearTimeout(_addrDebounceTimer);
    _addrDebounceTimer = setTimeout(() => fetchAddrSuggestions(q), 300);
  });

  input.addEventListener('keydown', e => {
    if (dropdown.style.display === 'none') return;
    const items  = [...dropdown.querySelectorAll('.addr-option')];
    const active = dropdown.querySelector('.addr-option.active');
    const idx    = items.indexOf(active);

    if (e.key === 'ArrowDown') {
      e.preventDefault();
      active?.classList.remove('active');
      items[idx + 1 < items.length ? idx + 1 : 0]?.classList.add('active');
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      active?.classList.remove('active');
      items[idx - 1 >= 0 ? idx - 1 : items.length - 1]?.classList.add('active');
    } else if (e.key === 'Enter') {
      e.preventDefault();
      active?.click();
    } else if (e.key === 'Escape') {
      closeAddrDropdown();
    }
  });

  document.addEventListener('click', e => {
    if (!e.target.closest('#addrAutocomplete')) closeAddrDropdown();
  });
}

async function fetchAddrSuggestions(query) {
  const dropdown = qs('#addrDropdown');
  if (!dropdown) return;
  dropdown.innerHTML = '<div class="addr-loading-msg">Zoeken…</div>';
  dropdown.style.display = '';

  try {
    const q = encodeURIComponent(query);
    const r = await fetch(`https://api.pdok.nl/bzk/locatieserver/search/v3_1/suggest?q=${q}&fq=type:adres&rows=6`);
    const d = await r.json();
    const docs = d?.response?.docs || [];

    if (!docs.length) {
      dropdown.innerHTML = '<div class="addr-no-results">Geen adressen gevonden</div>';
      return;
    }

    dropdown.innerHTML = docs.map(doc => `
      <div class="addr-option"
           data-id="${escHtml(doc.id)}"
           data-label="${escHtml(doc.weergavenaam)}"
           onclick="selectDeliveryAddress(this.dataset.id, this.dataset.label)">
        ${escHtml(doc.weergavenaam)}
      </div>`).join('');
  } catch {
    closeAddrDropdown();
  }
}

async function selectDeliveryAddress(id, label) {
  const input = qs('#fAdres');
  if (!input) return;

  closeAddrDropdown();
  input.value = label;
  input.classList.add('addr-loading');
  selectedDeliveryAddress = null;

  try {
    const r = await fetch(`https://api.pdok.nl/bzk/locatieserver/search/v3_1/lookup?id=${encodeURIComponent(id)}`);
    const d = await r.json();
    const doc = d?.response?.docs?.[0];
    if (doc?.centroide_ll) {
      /* centroide_ll format: "POINT(lon lat)" */
      const [lng, lat] = doc.centroide_ll.replace('POINT(', '').replace(')', '').split(' ').map(Number);
      selectedDeliveryAddress = { label, lat, lng };
      input.classList.replace('addr-loading', 'addr-selected');
    } else {
      input.classList.remove('addr-loading');
    }
  } catch {
    input.classList.remove('addr-loading');
  }
}

function closeAddrDropdown() {
  const el = qs('#addrDropdown');
  if (el) el.style.display = 'none';
}

function showAddrError(msg) {
  const el = qs('#addrError');
  if (el) { el.textContent = msg; el.style.display = ''; }
  qs('#fAdres')?.classList.add('input-error');
}

function clearAddrError() {
  const el = qs('#addrError');
  if (el) el.style.display = 'none';
  qs('#fAdres')?.classList.remove('input-error');
}

function escHtml(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

/* ── PHONE VALIDATION ────────────────────────────────────────── */
function initPhoneValidation() {
  const tel = qs('#fTel');
  if (!tel) return;
  tel.addEventListener('blur',  () => { if (tel.value.trim()) validatePhone(); });
  tel.addEventListener('input', clearTelError);
}

function isValidDutchPhone(raw) {
  let s = raw.replace(/[\s()\-\.]/g, '');
  if (s.startsWith('+')) s = s.slice(1);
  if (s.startsWith('0031')) s = '0' + s.slice(4);
  if (s.startsWith('31') && s.length === 11) s = '0' + s.slice(2);
  return /^0[1-9]\d{8}$/.test(s);
}

function validatePhone() {
  const v = val('fTel');
  if (!isValidDutchPhone(v)) showTelError('Voer een geldig Nederlands telefoonnummer in (bijv. 06 12 34 56 78).');
}

function showTelError(msg) {
  const el = qs('#telError');
  if (el) { el.textContent = msg; el.style.display = ''; }
  qs('#fTel')?.classList.add('input-error');
}

function clearTelError() {
  const el = qs('#telError');
  if (el) el.style.display = 'none';
  qs('#fTel')?.classList.remove('input-error');
}

/* ── EMAIL VALIDATION ────────────────────────────────────────── */
function initEmailValidation() {
  const email = qs('#fEmail');
  if (!email) return;
  email.addEventListener('blur',  () => { if (email.value.trim()) validateEmail(); });
  email.addEventListener('input', clearEmailError);
}

function isValidEmail(v) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);
}

function validateEmail() {
  if (!isValidEmail(val('fEmail'))) showEmailError('Voer een geldig e-mailadres in (bijv. naam@voorbeeld.nl).');
}

function showEmailError(msg) {
  const el = qs('#emailError');
  if (el) { el.textContent = msg; el.style.display = ''; }
  qs('#fEmail')?.classList.add('input-error');
}

function clearEmailError() {
  const el = qs('#emailError');
  if (el) el.style.display = 'none';
  qs('#fEmail')?.classList.remove('input-error');
}

/* ── COUPON ──────────────────────────────────────────────────── */
function initCouponInput() {
  ['sidebar', 'drawer'].forEach(scope => {
    const input = qs(`#couponInput-${scope}`);
    if (!input) return;
    input.addEventListener('keydown', e => {
      if (e.key === 'Enter') { e.preventDefault(); applyCoupon(scope); }
    });
    input.addEventListener('input', () => {
      const errEl = qs(`#couponError-${scope}`);
      if (errEl) errEl.style.display = 'none';
    });
  });
}

function toggleCouponInput(scope) {
  const fieldRow = qs(`#couponFieldRow-${scope}`);
  if (!fieldRow) return;
  const isOpen = fieldRow.style.display !== 'none';
  fieldRow.style.display = isOpen ? 'none' : '';
  if (!isOpen) qs(`#couponInput-${scope}`)?.focus();
}

function applyCoupon(scope) {
  const input = qs(`#couponInput-${scope}`);
  const code  = (input?.value || '').trim().toUpperCase();
  const errEl = qs(`#couponError-${scope}`);
  if (errEl) errEl.style.display = 'none';
  if (!code) return;

  const discount = COUPONS[code];
  if (discount) {
    couponCode     = code;
    couponDiscount = discount;
    qAll('[id^="couponFieldRow-"]').forEach(el => el.style.display = 'none');
    updateCouponUI();
    renderTipBtns(discountedTotal());
    updateTipUI();
  } else {
    if (errEl) { errEl.textContent = 'Ongeldige kortingscode.'; errEl.style.display = ''; }
  }
}

function removeCoupon() {
  couponCode     = '';
  couponDiscount = 0;
  qAll('[id^="couponInput-"]').forEach(el => el.value = '');
  updateCouponUI();
  renderTipBtns(discountedTotal());
  updateTipUI();
}

function updateCouponUI() {
  const total     = cartTotal();
  const discAmt   = +(total * couponDiscount).toFixed(2);
  const hasCoupon = couponDiscount > 0;

  qAll('[data-coupon-toggle]').forEach(el => el.style.display = hasCoupon ? 'none' : '');
  qAll('[data-coupon-applied]').forEach(el => el.style.display = hasCoupon ? '' : 'none');
  qAll('[data-coupon-after-disc]').forEach(el => el.style.display = hasCoupon ? '' : 'none');

  if (hasCoupon) {
    qAll('[data-coupon-applied-label]').forEach(el => el.textContent = `Korting (${couponCode})`);
    qAll('[data-coupon-applied-amt]').forEach(el => el.textContent = '−' + fmt(discAmt));
    qAll('[data-coupon-after-disc-amt]').forEach(el => el.textContent = fmt(discountedTotal()));
  }

  /* Dim the original cart total when a discount is active */
  qAll('[data-cart-total]').forEach(el => el.style.color = hasCoupon ? 'var(--grey-400)' : '');

  /* Sync checkout modal VAT row */
  const coVat = qs('#coVatRow');
  if (coVat) {
    const factor    = 1 - couponDiscount;
    const breakdown = getVatBreakdown();
    const vStr = breakdown
      .map(v => `waarvan BTW (${v.rate}%): ${fmt(v.amount * factor)}`)
      .join('<br>');
    coVat.innerHTML = vStr;
    coVat.style.display = vStr ? '' : 'none';
  }
}

/* ── TIP ─────────────────────────────────────────────────────── */
function initTipInput() {
  const input = qs('#tipCustom');
  if (!input) return;
  input.addEventListener('input', () => {
    tipAmount = Math.max(0, parseFloat(input.value) || 0);
    updateTipUI();
  });
}

function renderTipBtns(subtotal) {
  const container = qs('#tipBtns');
  if (!container) return;
  /* Round up to the first multiple of €5 whose tip falls within the 4–20% window.
     Work in integer cents to avoid float drift. */
  const cents          = Math.round(subtotal * 100);
  const minTargetCents = Math.ceil(cents * 1.04);           // smallest target satisfying ≥4%
  const targetCents    = Math.ceil(minTargetCents / 500) * 500; // snap up to next ×€5
  const roundUp        = +((targetCents - cents) / 100).toFixed(2);
  const ruRatio        = subtotal > 0 ? roundUp / subtotal : 0;
  const showRoundUp    = ruRatio >= 0.04 && ruRatio <= 0.20;
  const btns = [
    ...(showRoundUp ? [{ key: 'roundup', html: `Afronden<br><small>+${fmt(roundUp)}</small>`, amount: roundUp }] : []),
    { key: '5',       html: '5%',           amount: +(subtotal * 0.05).toFixed(2) },
    { key: '10',      html: '10%',          amount: +(subtotal * 0.10).toFixed(2) },
    { key: '20',      html: '20%',          amount: +(subtotal * 0.20).toFixed(2) },
    { key: 'custom',  html: 'Eigen bedrag', amount: null },
  ];
  container.innerHTML = btns.map(b =>
    `<button class="tip-btn" data-key="${b.key}" onclick="selectTip('${b.key}',${b.amount})">${b.html}</button>`
  ).join('');
}

function selectTip(key, amount) {
  const btn        = qs(`#tipBtns [data-key="${key}"]`);
  const wasSelected = btn?.classList.contains('selected');

  qAll('#tipBtns .tip-btn').forEach(b => b.classList.remove('selected'));
  const customWrap = qs('#tipCustomWrap');
  if (customWrap) customWrap.style.display = 'none';
  tipAmount = 0;

  if (!wasSelected) {
    btn?.classList.add('selected');
    if (key === 'custom') {
      if (customWrap) customWrap.style.display = '';
      const input = qs('#tipCustom');
      if (input) { input.focus(); tipAmount = Math.max(0, parseFloat(input.value) || 0); }
    } else {
      tipAmount = amount ?? 0;
    }
  }
  updateTipUI();
}

function updateTipUI() {
  const base      = discountedTotal();
  const hasCoupon = couponDiscount > 0;
  const tipRow    = qs('#coTipRow');
  const grandRow  = qs('#coGrandRow');
  const totalEl   = qs('#coTotal');

  if (tipAmount > 0) {
    const tipAmtEl = qs('#coTipAmt');
    const grandEl  = qs('#coGrand');
    if (tipAmtEl) tipAmtEl.textContent = fmt(tipAmount);
    if (grandEl)  grandEl.textContent  = fmt(base + tipAmount);
    if (tipRow)   tipRow.style.display   = '';
    if (grandRow) grandRow.style.display = '';
    if (totalEl)  totalEl.style.color    = 'var(--grey-600)';
    if (hasCoupon) qAll('[data-coupon-after-disc-amt]').forEach(el => el.style.color = 'var(--grey-600)');
  } else {
    if (tipRow)   tipRow.style.display   = 'none';
    if (grandRow) grandRow.style.display = 'none';
    if (totalEl)  totalEl.style.color    = hasCoupon ? 'var(--grey-600)' : 'var(--primary)';
    if (hasCoupon) qAll('[data-coupon-after-disc-amt]').forEach(el => el.style.color = '');
  }
}

/* ── SCHEDULING ──────────────────────────────────────────────── */

/* Returns { day (0-6), min (0-1439) } in Amsterdam local time for any Date */
function getAmsterdamParts(date) {
  const parts = new Intl.DateTimeFormat('en-GB', {
    timeZone: 'Europe/Amsterdam',
    weekday: 'short', hour: '2-digit', minute: '2-digit', hour12: false,
  }).formatToParts(date);
  const dayMap = { Sun:0, Mon:1, Tue:2, Wed:3, Thu:4, Fri:5, Sat:6 };
  const day = dayMap[parts.find(p => p.type === 'weekday')?.value] ?? 0;
  const h   = parseInt(parts.find(p => p.type === 'hour')?.value   || 0);
  const m   = parseInt(parts.find(p => p.type === 'minute')?.value || 0);
  return { day, min: h * 60 + m };
}

function getAmsterdamDayMin() { return getAmsterdamParts(new Date()); }

/* True if two Date objects fall on the same Amsterdam calendar day */
function isSameAmsterdamDay(a, b) {
  const fmt = d => new Intl.DateTimeFormat('en-CA', { timeZone: 'Europe/Amsterdam' }).format(d);
  return fmt(a) === fmt(b);
}

/* Convert an Amsterdam ISO date string ('YYYY-MM-DD') to a Date (noon UTC — always same day in Amsterdam) */
function dateFromAmsterdamISO(isoDate) {
  return new Date(`${isoDate}T12:00:00Z`);
}

/* Extract { year, month (1-12), day } from a Date in Amsterdam timezone */
function getAmsterdamDateParts(date) {
  const iso = new Intl.DateTimeFormat('en-CA', { timeZone: 'Europe/Amsterdam' }).format(date);
  const [y, m, d] = iso.split('-').map(Number);
  return { year: y, month: m, day: d };
}

/* Returns the schedule entry for a given Date, or null if closed that day */
function getScheduleEntryForDate(date) {
  if (!BRAND.schedule?.length) return null;
  const { day } = getAmsterdamParts(date);
  return BRAND.schedule.find(s => s.days.includes(day)) || null;
}

function getTodayScheduleEntry() { return getScheduleEntryForDate(new Date()); }

/* Returns an array of 'HH:MM' strings for the given date (defaults to today) */
function generateTimeSlots(method, date = new Date()) {
  const entry = getScheduleEntryForDate(date);
  if (!entry) return [];

  const cfg      = BRAND.scheduling || {};
  const prepMin  = method === 'pickup'
    ? (cfg.pickup_prep_min  ?? 20)
    : (cfg.delivery_prep_min ?? 35);
  const interval = cfg.slot_interval_min ?? 15;

  const [oh, om] = entry.open.split(':').map(Number);
  const [ch, cm] = entry.close.split(':').map(Number);
  const openMin  = oh * 60 + om;
  const closeMin = (ch === 0 && cm === 0) ? 24 * 60 : ch * 60 + cm;

  const isToday = isSameAmsterdamDay(date, new Date());
  const nowMin  = isToday ? getAmsterdamDayMin().min : 0;

  const earliest  = Math.max(openMin + prepMin, nowMin + prepMin);
  const firstSlot = Math.ceil(earliest / interval) * interval;

  const slots = [];
  for (let t = firstSlot; t < closeMin; t += interval) {
    const hh = Math.floor(t / 60);
    if (hh >= 24) break;
    slots.push(`${String(hh).padStart(2,'0')}:${String(t % 60).padStart(2,'0')}`);
  }
  return slots;
}

/* ── CALENDAR POPUP ─────────────────────────────────────────── */
function toggleCalPopup() {
  const popup = qs('#calPopup');
  if (!popup) return;
  if (popup.style.display !== 'none') {
    closeCalPopup();
  } else {
    popup.style.display = '';
    renderCalendar();
  }
}

function closeCalPopup() {
  const popup = qs('#calPopup');
  if (popup) popup.style.display = 'none';
}

function formatOrderDateLabel(isoDate) {
  if (!isoDate) return 'Kies een datum';
  const d      = dateFromAmsterdamISO(isoDate);
  const todayP = getAmsterdamDateParts(new Date());
  const selP   = getAmsterdamDateParts(d);
  if (selP.year === todayP.year && selP.month === todayP.month && selP.day === todayP.day) return 'Vandaag';
  const tmrw  = new Date(); tmrw.setDate(tmrw.getDate() + 1);
  const tmrwP = getAmsterdamDateParts(tmrw);
  if (selP.year === tmrwP.year && selP.month === tmrwP.month && selP.day === tmrwP.day) return 'Morgen';
  return new Intl.DateTimeFormat('nl-NL', {
    timeZone: 'Europe/Amsterdam', weekday: 'short', day: 'numeric', month: 'short',
  }).format(d);
}

function updateCalTriggerLabel() {
  const el = qs('#calTriggerLabel');
  if (el) el.textContent = formatOrderDateLabel(selectedOrderDate);
}

/* Returns the ISO date of the first day with available time slots */
function getFirstAvailableDate() {
  const maxDays = BRAND.scheduling?.max_days_ahead ?? 0;
  const now     = new Date();
  for (let i = 0; i <= maxDays; i++) {
    const d = new Date(now);
    d.setDate(d.getDate() + i);
    if (generateTimeSlots(fulfillMethod, d).length > 0) {
      return new Intl.DateTimeFormat('en-CA', { timeZone: 'Europe/Amsterdam' }).format(d);
    }
  }
  return null;
}

/* Switches between ASAP and Scheduled timing modes */
function selectTiming(mode) {
  timingMode = mode;
  qs('#tOptAsap')?.classList.toggle('selected',      mode === 'asap');
  qs('#tOptScheduled')?.classList.toggle('selected', mode === 'scheduled');

  const section = qs('#scheduledSection');
  if (section) section.style.display = mode === 'scheduled' ? '' : 'none';

  if (mode === 'scheduled') {
    if (!selectedOrderDate) selectedOrderDate = getFirstAvailableDate();
    updateCalTriggerLabel();
    const maxDays  = BRAND.scheduling?.max_days_ahead ?? 0;
    const calField = qs('#calField');
    if (calField) calField.style.display = maxDays > 0 ? '' : 'none';
    initScheduling();
  }

  const errEl = qs('#timeError');
  if (errEl) errEl.style.display = 'none';
}

/* Renders the month-grid calendar for calYear / calMonth */
function renderCalendar() {
  const container = qs('#calWrap');
  if (!container) return;

  const maxDays = BRAND.scheduling?.max_days_ahead ?? 0;
  if (maxDays < 1) return;

  const todayParts = getAmsterdamDateParts(new Date());
  const lastD      = new Date(); lastD.setDate(lastD.getDate() + maxDays);
  const lastParts  = getAmsterdamDateParts(lastD);

  /* First day of displayed month at noon UTC */
  const firstOfMonth = new Date(`${calYear}-${String(calMonth).padStart(2,'0')}-01T12:00:00Z`);
  const { day: firstDow } = getAmsterdamParts(firstOfMonth); // 0=Sun…6=Sat
  const dutchOffset       = firstDow === 0 ? 6 : firstDow - 1; // Mon=0 offset

  /* Days in displayed month */
  const nextM          = calMonth === 12 ? 1  : calMonth + 1;
  const nextY          = calMonth === 12 ? calYear + 1 : calYear;
  const lastOfMonth    = new Date(`${nextY}-${String(nextM).padStart(2,'0')}-01T12:00:00Z`);
  lastOfMonth.setUTCDate(lastOfMonth.getUTCDate() - 1);
  const daysInMonth    = getAmsterdamDateParts(lastOfMonth).day;

  /* Dutch month label, capitalised */
  const rawLabel      = new Intl.DateTimeFormat('nl-NL', {
    timeZone: 'Europe/Amsterdam', month: 'long', year: 'numeric',
  }).format(firstOfMonth);
  const monthLabel    = rawLabel.charAt(0).toUpperCase() + rawLabel.slice(1);

  const canPrev = calYear > todayParts.year || (calYear === todayParts.year && calMonth > todayParts.month);
  const canNext = lastParts.year > calYear  || (lastParts.year === calYear  && lastParts.month > calMonth);

  const dowCells   = ['Ma','Di','Wo','Do','Vr','Za','Zo'].map(d => `<div class="cal-dow">${d}</div>`).join('');
  const emptyCells = Array(dutchOffset).fill('<div class="cal-day cal-empty"></div>').join('');

  const dayCells = Array.from({ length: daysInMonth }, (_, i) => {
    const dayNum   = i + 1;
    const isoDate  = `${calYear}-${String(calMonth).padStart(2,'0')}-${String(dayNum).padStart(2,'0')}`;
    const cellDate = new Date(`${isoDate}T12:00:00Z`);

    const isPast = calYear < todayParts.year
      || (calYear === todayParts.year && calMonth < todayParts.month)
      || (calYear === todayParts.year && calMonth === todayParts.month && dayNum < todayParts.day);
    const isBeyond = calYear > lastParts.year
      || (calYear === lastParts.year && calMonth > lastParts.month)
      || (calYear === lastParts.year && calMonth === lastParts.month && dayNum > lastParts.day);
    const isClosed   = !getScheduleEntryForDate(cellDate);
    const isDisabled = isPast || isBeyond || isClosed;
    const isToday    = calYear === todayParts.year && calMonth === todayParts.month && dayNum === todayParts.day;
    const isSelected = isoDate === selectedOrderDate;

    let cls = 'cal-day';
    if (isDisabled)       cls += ' cal-disabled';
    else if (isSelected)  cls += ' cal-selected';
    else if (isToday)     cls += ' cal-today';

    return isDisabled
      ? `<div class="${cls}">${dayNum}</div>`
      : `<div class="${cls}" onclick="selectCalDay(this,'${isoDate}')">${dayNum}</div>`;
  }).join('');

  container.innerHTML = `
    <div class="cal-nav">
      <button class="cal-nav-btn" onclick="calNavigate(-1)" ${canPrev ? '' : 'disabled'}>‹</button>
      <span class="cal-month-lbl">${monthLabel}</span>
      <button class="cal-nav-btn" onclick="calNavigate(1)"  ${canNext ? '' : 'disabled'}>›</button>
    </div>
    <div class="cal-grid">${dowCells}${emptyCells}${dayCells}</div>`;
}

function calNavigate(dir) {
  calMonth += dir;
  if (calMonth > 12) { calMonth = 1;  calYear++; }
  if (calMonth < 1)  { calMonth = 12; calYear--; }
  renderCalendar();
}

function selectCalDay(btn, isoDate) {
  selectedOrderDate = isoDate;
  closeCalPopup();
  updateCalTriggerLabel();
  initScheduling();
}

/* Updates the ASAP description and repopulates #fTijd for the selected date */
function initScheduling() {
  const cfg     = BRAND.scheduling || {};
  const prepMin = fulfillMethod === 'pickup'
    ? (cfg.pickup_prep_min  ?? 20)
    : (cfg.delivery_prep_min ?? 35);

  const asapDesc = qs('#asapDesc');
  if (asapDesc) asapDesc.textContent = `~${prepMin} min`;

  const sel = qs('#fTijd');
  if (!sel || timingMode !== 'scheduled') return;

  const targetDate = selectedOrderDate ? dateFromAmsterdamISO(selectedOrderDate) : new Date();
  const slots      = generateTimeSlots(fulfillMethod, targetDate);

  sel.innerHTML = slots.map(t => `<option value="${t}">${t}</option>`).join('');
  if (slots.length) sel.value = slots[0];

  const errEl = qs('#timeError');
  if (errEl) errEl.style.display = 'none';
}

/* ── WHATSAPP ────────────────────────────────────────────────── */
function openWhatsApp() {
  const lines = Object.entries(cart).map(([id, qty]) => {
    const item = ITEM_MAP[id];
    return `• ${item.name} ×${qty} — ${fmt(item.price * qty)}`;
  }).join('\n');

  const note    = val('fNote');
  const pay     = payMethod === 'ideal' ? 'iDEAL' : (fulfillMethod === 'pickup' ? 'Contant bij afhalen' : 'Contant bij bezorging');
  const fulfill = fulfillMethod === 'pickup' ? 'Afhalen' : 'Bezorgen';
  const addrLine = fulfillMethod === 'pickup'
    ? `Afhalen op: ${BRAND.address.street}, ${BRAND.address.postal} ${BRAND.address.city}`
    : `Bezorgadres: ${val('fAdres')}`;

  const msg = [
    `Nieuwe bestelling — ${BRAND.name}`,
    '',
    `Naam: ${val('fNaam')}`,
    `Telefoon: ${val('fTel')}`,
    `E-mail: ${val('fEmail')}`,
    addrLine,
    `Bezorgwijze: ${fulfill}`,
    `Gewenste tijd: ${(() => {
      if (!scheduledTime || scheduledTime === 'asap') return 'Zo snel mogelijk';
      const td = selectedOrderDate ? dateFromAmsterdamISO(selectedOrderDate) : new Date();
      if (isSameAmsterdamDay(td, new Date())) return scheduledTime;
      const dateLbl = new Intl.DateTimeFormat('nl-NL', {
        timeZone: 'Europe/Amsterdam', weekday: 'long', day: 'numeric', month: 'long',
      }).format(td);
      return `${dateLbl} om ${scheduledTime}`;
    })()}`,
    note ? `Opmerking: ${note}` : null,
    `Betaling: ${pay}`,
    '',
    'Bestelling:',
    lines,
    '',
    ...(() => {
      const base  = cartTotal();
      const disc  = +(base * couponDiscount).toFixed(2);
      const after = discountedTotal();
      const ls    = [];
      if (couponDiscount > 0 || tipAmount > 0) ls.push(`Subtotaal: ${fmt(base)}`);
      if (couponDiscount > 0) ls.push(`Korting (${couponCode}): −${fmt(disc)}`);
      if (tipAmount > 0)      ls.push(`Fooi: ${fmt(tipAmount)}`);
      ls.push(`Totaal: ${fmt(after + tipAmount)}`);
      return ls;
    })(),
  ].filter(l => l !== null).join('\n');

  window.open(`https://wa.me/${BRAND.whatsapp}?text=${encodeURIComponent(msg)}`, '_blank');
}

/* ── CHECKOUT FIELD PERSISTENCE ─────────────────────────────── */
function saveCheckoutFields() {
  try {
    localStorage.setItem(CHECKOUT_FIELDS_KEY, JSON.stringify({
      naam:  val('fNaam'),
      tel:   val('fTel'),
      email: val('fEmail'),
      adres: val('fAdres'),
      addr:  selectedDeliveryAddress,
      note:  val('fNote'),
    }));
  } catch {}
}

function restoreCheckoutFields() {
  let saved;
  try { saved = JSON.parse(localStorage.getItem(CHECKOUT_FIELDS_KEY) || 'null'); } catch {}
  if (!saved) return;

  const setVal = (id, v) => { const el = qs(`#${id}`); if (el && v) el.value = v; };
  setVal('fNaam',  saved.naam);
  setVal('fTel',   saved.tel);
  setVal('fEmail', saved.email);
  setVal('fNote',  saved.note);

  if (saved.adres && saved.addr) {
    const adres = qs('#fAdres');
    if (adres) {
      adres.value = saved.adres;
      adres.classList.add('addr-selected');
      selectedDeliveryAddress = saved.addr;
    }
  }
}

/* ── NEW ORDER ───────────────────────────────────────────────── */
function newOrder() {
  try { localStorage.removeItem(CART_KEY); } catch {}
  /* Keep personal details for next order but clear the note */
  try {
    const saved = JSON.parse(localStorage.getItem(CHECKOUT_FIELDS_KEY) || '{}');
    localStorage.setItem(CHECKOUT_FIELDS_KEY, JSON.stringify({
      naam:  saved.naam  || '',
      tel:   saved.tel   || '',
      email: saved.email || '',
      adres: saved.adres || '',
      addr:  saved.addr  || null,
      note:  '',
    }));
  } catch {}
  Object.keys(cart).forEach(id => { delete cart[id]; refreshCtrl(id); });
  refreshUI();
  ['fNaam','fTel','fEmail','fAdres','fNote'].forEach(id => {
    const el = qs(`#${id}`);
    if (el) el.value = '';
  });
  qs('#fAdres')?.classList.remove('addr-selected', 'addr-loading');
  clearTelError();
  clearEmailError();
  tipAmount      = 0;
  couponCode     = '';
  couponDiscount = 0;
  qAll('[id^="couponInput-"]').forEach(el => el.value = '');
  updateCouponUI();
  scheduledTime     = null;
  selectedOrderDate = null;
  timingMode        = 'asap';
  calYear           = null;
  calMonth          = null;
  selectPay('ideal');
  selectFulfillment('delivery');
  qs('#confirmScreen')?.classList.remove('open');
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

/* ── OPENING HOURS CHECK ─────────────────────────────────────── */
/**
 * Reads BRAND.schedule and Amsterdam local time.
 * Returns true if the restaurant is currently open.
 */
function isRestaurantOpen() {
  if (!BRAND.schedule || !BRAND.schedule.length) return true;
  const { day, min: now } = getAmsterdamParts(new Date());
  for (const slot of BRAND.schedule) {
    if (!slot.days.includes(day)) continue;
    const [oh, om] = slot.open.split(':').map(Number);
    const [ch, cm] = slot.close.split(':').map(Number);
    const openMin  = oh * 60 + om;
    const closeMin = (ch === 0 && cm === 0) ? 24 * 60 : ch * 60 + cm;
    if (now >= openMin && now < closeMin) return true;
  }
  return false;
}

/**
 * Returns a human-readable Dutch string like
 * "We openen vandaag om 12:00" or "We openen morgen om 12:00".
 */
function getNextOpenMsg() {
  if (!BRAND.schedule || !BRAND.schedule.length) return '';
  const dayNames = ['zondag','maandag','dinsdag','woensdag','donderdag','vrijdag','zaterdag'];

  for (let ahead = 0; ahead <= 7; ahead++) {
    const d = new Date();
    d.setDate(d.getDate() + ahead);

    const parts = new Intl.DateTimeFormat('en-GB', {
      timeZone: 'Europe/Amsterdam',
      weekday: 'short',
      hour: '2-digit', minute: '2-digit', hour12: false,
    }).formatToParts(d);

    const dayMap = { Sun:0, Mon:1, Tue:2, Wed:3, Thu:4, Fri:5, Sat:6 };
    const dayIdx = dayMap[parts.find(p => p.type === 'weekday')?.value];
    const h      = parseInt(parts.find(p => p.type === 'hour')?.value   || 0);
    const m      = parseInt(parts.find(p => p.type === 'minute')?.value || 0);
    const nowMin = h * 60 + m;

    for (const slot of BRAND.schedule) {
      if (!slot.days.includes(dayIdx)) continue;
      const [oh, om] = slot.open.split(':').map(Number);
      const openMin  = oh * 60 + om;

      /* Today: skip if we're at or past the opening (closed for the day) */
      if (ahead === 0 && nowMin >= openMin) continue;

      const label = ahead === 0 ? 'vandaag' : ahead === 1 ? 'morgen' : dayNames[dayIdx];
      return `We openen ${label} om ${slot.open}`;
    }
  }
  return '';
}

/**
 * Runs on page load. Shows the closed banner and disables order
 * buttons when outside opening hours.
 */
function initOpenCheck() {
  restaurantOpen = isRestaurantOpen();
  if (restaurantOpen) return;

  const banner = qs('#closedBanner');
  if (!banner) return;
  banner.style.display = '';
  qs('.order-layout')?.classList.add('has-closed-banner');
  document.documentElement.style.setProperty('--banner-h', banner.offsetHeight + 'px');

  const msgEl = qs('#closedMsg');
  if (msgEl) {
    const next = getNextOpenMsg();
    msgEl.textContent = next ? ` · ${next}` : '';
  }
}

/* ── CATEGORY SCROLL + OBSERVER ─────────────────────────────── */
function goToCategory(catId, btn) {
  const section = qs(`#ms-${catId}`);
  if (!section) return;

  const navH  = qs('.site-nav')?.offsetHeight || 0;
  const tabsH = qs('.mobile-tabs-wrap')?.offsetHeight || 0;
  const top   = section.getBoundingClientRect().top + window.pageYOffset - navH - tabsH - 6;
  window.scrollTo({ top, behavior: 'smooth' });

  const parentId = btn.closest('#catSidebar') ? '#catSidebar' : '#mobileTabs';
  qAll(`${parentId} button`).forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
}

function initScrollSpy() {
  const observer = new IntersectionObserver(entries => {
    entries.forEach(entry => {
      if (!entry.isIntersecting) return;
      const catId = entry.target.id.replace('ms-', '');
      ['#catSidebar','#mobileTabs'].forEach(pid => {
        const parent = qs(pid);
        if (!parent) return;
        qAll(`${pid} button`).forEach(b => b.classList.remove('active'));
        const activeBtn = parent.querySelector(`[data-target="${catId}"]`);
        if (activeBtn) {
          activeBtn.classList.add('active');
          activeBtn.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
        }
      });
    });
  }, { rootMargin: '-12% 0px -75% 0px' });

  qAll('.menu-section').forEach(el => observer.observe(el));
}

/* ── NAV SCROLL EFFECT ───────────────────────────────────────── */
function initNavScroll() {
  const nav = qs('.site-nav');
  if (!nav) return;
  window.addEventListener('scroll', () => {
    nav.classList.toggle('scrolled', window.scrollY > 50);
  }, { passive: true });
}

/* ── CART ICON ANIMATION ─────────────────────────────────────── */
function bumpCartIcon() {
  qAll('.cart-anim').forEach(el => {
    el.classList.remove('bounce');
    void el.offsetWidth;
    el.classList.add('bounce');
    el.addEventListener('animationend', () => el.classList.remove('bounce'), { once: true });
  });
}

/* ── MOBILE NAV ──────────────────────────────────────────────── */
function closeMobileNav() {
  qs('#mobileMenu')?.classList.remove('open');
}

function toggleMobileNav() {
  qs('#mobileMenu')?.classList.toggle('open');
}

function initMobileNav() {
  window.addEventListener('scroll', closeMobileNav, { passive: true });
  document.addEventListener('click', e => {
    if (!qs('#mobileMenu')?.classList.contains('open')) return;
    if (!e.target.closest('#mobileMenu') && !e.target.closest('.nav-hamburger')) closeMobileNav();
  });
}

/* ── CART PERSISTENCE ────────────────────────────────────────── */
function saveCart() {
  try { localStorage.setItem(CART_KEY, JSON.stringify(cart)); } catch {}
}

function loadCart() {
  try {
    const stored = localStorage.getItem(CART_KEY);
    if (!stored) return;
    const data = JSON.parse(stored);
    Object.entries(data).forEach(([id, qty]) => {
      if (ITEM_MAP[id] && Number.isInteger(qty) && qty > 0) cart[id] = qty;
    });
  } catch {}
}

/* ── VAT ─────────────────────────────────────────────────────── */
function getVatBreakdown() {
  const groups = {};
  Object.entries(cart).forEach(([id, qty]) => {
    const cat  = MENU.find(c => c.items.some(i => i.id === id));
    const rate = cat?.vat_rate ?? 9;
    groups[rate] = (groups[rate] || 0) + ITEM_MAP[id].price * qty;
  });
  return Object.entries(groups)
    .sort(([a], [b]) => Number(a) - Number(b))
    .map(([rate, subtotal]) => ({
      rate: Number(rate),
      amount: subtotal * Number(rate) / (100 + Number(rate)),
    }));
}

function vatHtml(breakdown, factor = 1) {
  return breakdown
    .map(v => `waarvan BTW (${v.rate}%): ${fmt(v.amount * factor)}`)
    .join('<br>');
}

/* ── UTILITY ─────────────────────────────────────────────────── */
const qs   = (sel, ctx = document) => ctx.querySelector(sel);
const qAll = (sel, ctx = document) => [...ctx.querySelectorAll(sel)];
const q    = (sel, fn) => { const el = qs(sel); if (el) fn(el); };
const val  = id => { const el = qs(`#${id}`); return el ? el.value.trim() : ''; };

function fmt(amount) {
  return BRAND.currency + ' ' + amount.toFixed(2).replace('.', ',');
}
